 * (`ISEKAI_PIPE_DESIGN.md` §8 Epic M、`isekai_protocol::ClipboardMime`全種)の両方が
 * 運べるmime種別。`isekai_protocol::ClipboardMime`をUniFFI境界越しにそのまま公開できない
 * (isekai-protocolはuniffiに依存しないpure crate)ため、ここに同型を用意する。
 */

enum class ClipboardMimeKind {
    
    TEXT_PLAIN,
    TEXT_HTML,
    IMAGE_PNG;

    


    companion object
}


/**
 * @suppress
 */
public object FfiConverterTypeClipboardMimeKind: FfiConverterRustBuffer<ClipboardMimeKind> {
    override fun read(buf: ByteBuffer) = try {
        ClipboardMimeKind.values()[buf.getInt() - 1]
    } catch (e: IndexOutOfBoundsException) {
        throw RuntimeException("invalid enum value, something is very wrong!!", e)
    }

    override fun allocationSize(value: ClipboardMimeKind) = 4UL

    override fun write(value: ClipboardMimeKind, buf: ByteBuffer) {
        buf.putInt(value.ordinal + 1)
    }
}





sealed class ConnectionPublicState {
    
    data class Disconnected(
        val `reason`: kotlin.String?) : ConnectionPublicState()
        
    {
        

        companion object
    }
    
    object Connecting : ConnectionPublicState()
    
    
    data class Connected(
        val `host`: kotlin.String) : ConnectionPublicState()
        
    {
        

        companion object
    }
    
    data class Error(
        val `message`: kotlin.String) : ConnectionPublicState()
        
    {
        

        companion object
    }
    
    /**
     * 一度`Connected`になったセッションが予期せず切断された際、orchestratorが
     * 自動的に再接続を試みている間の状態(`orchestrator.rs`のreconnectループ参照)。
     * `elapsed_secs`/`timeout_secs`はUIがライブなカウントダウンを描画するための
     * SSOT値(Kotlin側でタイマーを持たない)。
     */
    data class Reconnecting(
        val `elapsedSecs`: kotlin.UInt, 
        val `timeoutSecs`: kotlin.UInt, 
        val `reason`: kotlin.String?) : ConnectionPublicState()
        
    {
        

        companion object
    }
    

    

    
    


    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeConnectionPublicState : FfiConverterRustBuffer<ConnectionPublicState>{
    override fun read(buf: ByteBuffer): ConnectionPublicState {
        return when(buf.getInt()) {
            1 -> ConnectionPublicState.Disconnected(
                FfiConverterOptionalString.read(buf),
                )
            2 -> ConnectionPublicState.Connecting
            3 -> ConnectionPublicState.Connected(
                FfiConverterString.read(buf),
                )
            4 -> ConnectionPublicState.Error(
                FfiConverterString.read(buf),
                )
            5 -> ConnectionPublicState.Reconnecting(
                FfiConverterUInt.read(buf),
                FfiConverterUInt.read(buf),
                FfiConverterOptionalString.read(buf),
                )
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: ConnectionPublicState) = when(value) {
        is ConnectionPublicState.Disconnected -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterOptionalString.allocationSize(value.`reason`)
            )
        }
        is ConnectionPublicState.Connecting -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is ConnectionPublicState.Connected -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`host`)
            )
        }
        is ConnectionPublicState.Error -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
        }
        is ConnectionPublicState.Reconnecting -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterUInt.allocationSize(value.`elapsedSecs`)
                + FfiConverterUInt.allocationSize(value.`timeoutSecs`)
                + FfiConverterOptionalString.allocationSize(value.`reason`)
            )
        }
    }

    override fun write(value: ConnectionPublicState, buf: ByteBuffer) {
        when(value) {
            is ConnectionPublicState.Disconnected -> {
                buf.putInt(1)
                FfiConverterOptionalString.write(value.`reason`, buf)
                Unit
            }
            is ConnectionPublicState.Connecting -> {
                buf.putInt(2)
                Unit
            }
            is ConnectionPublicState.Connected -> {
                buf.putInt(3)
                FfiConverterString.write(value.`host`, buf)
                Unit
            }
            is ConnectionPublicState.Error -> {
