                FfiConverterUInt.write(value.`timeoutSecs`, buf)
                FfiConverterOptionalString.write(value.`reason`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}





